package sn.gestionimmobiliere.backend.reminder.domain;
import java.time.Instant;import java.util.UUID;import jakarta.persistence.*;
@Entity @Table(name="reminders") public class Reminder{@Id private UUID id;@Column(name="organization_id")private UUID organizationId;@Column(name="rent_charge_id")private UUID rentChargeId;private String phone;private String message;@Column(name="prepared_at")private Instant preparedAt;protected Reminder(){}public Reminder(UUID id,UUID org,UUID charge,String phone,String message,Instant at){this.id=id;organizationId=org;rentChargeId=charge;this.phone=phone;this.message=message;preparedAt=at;}public UUID getId(){return id;}public String getPhone(){return phone;}public String getMessage(){return message;}public Instant getPreparedAt(){return preparedAt;}}
